/**
 * @author 纷享-曹树斌
 * @codeName 【计划任务】产品目录每日自检
 * @description 全量产品目录：拼全链路上级名称写入全链路；按是否有子级更新是否最子级
 * @createTime 2026-03-18
 * @bindingObjectLabel 产品目录
 * @bindingObjectApiName ProductCategoryObj
 * @函数需求编号
 */

final String CATALOG_OBJ = "ProductCategoryObj"
final String F_PARENT = "pid"
final String F_CATALOG_NAME = "name"
final String F_FULL_CHAIN = "product_catalogfull_link__c"
final String F_IS_MOST_SUB = "is_most_sub_level__c"
/** 全链路名称分隔符（单斜杠） */
final String CHAIN_SEP = "/"
final int QUERY_LIMIT = 10000

def (Boolean findErr, QueryResult qr, String findMsg) = Fx.object.find(
        CATALOG_OBJ,
        FQLAttribute.builder()
                .columns(["_id", F_PARENT, F_CATALOG_NAME])
                .queryTemplate(QueryTemplate.AND(["_id": QueryOperator.NE("")]))
                .limit(QUERY_LIMIT)
                .build(),
        SelectAttribute.builder().build())
if (findErr) {
    log.error("[产品目录自检] 查询失败：" + findMsg)
    return
}
List rows = qr?.dataList as List
if (!rows) {
    log.info("[产品目录自检] 无数据")
    return
}
log.info("[产品目录自检] 待处理条数=" + rows.size())

Map<String, String> idToParent = [:]
Map<String, String> idToName = [:]
Map<String, Integer> childCountByParentId = [:]
rows.each { r ->
    Map row = r as Map
    String id = (row["_id"] != null) ? row["_id"].toString() : ""
    if (!id) {
        return
    }
    Object pRaw = row[F_PARENT]
    String pid = ""
    if (pRaw instanceof List && (pRaw as List).size() > 0) {
        pid = (pRaw as List)[0] != null ? (pRaw as List)[0].toString() : ""
    } else if (pRaw != null) {
        pid = pRaw.toString()
    }
    idToParent[id] = pid
    idToName[id] = (row[F_CATALOG_NAME] ?: "") as String
    if (pid) {
        childCountByParentId[pid] = (childCountByParentId[pid] ?: 0) + 1
    }
}

List chainPartsRecursive(String cid, List acc, Set visited, int depth, String originId, Map idToParent, Map idToName) {
    if (!cid || depth >= 200) {
        return acc
    }
    if (visited.contains(cid)) {
        log.error("[产品目录自检] 检测到环，_id=" + originId)
        return acc
    }
    visited.add(cid)
    acc.add(0, (idToName[cid] ?: "") as String)
    String next = (idToParent[cid] ?: "") as String
    if (!next) {
        return acc
    }
    return chainPartsRecursive(next, acc, visited, depth + 1, originId, idToParent, idToName)
}

String buildFullChain(String startId, Map idToParent, Map idToName, String sep) {
    List parts = chainPartsRecursive(startId, [], [] as Set, 0, startId, idToParent, idToName).findAll { it }
    StringBuilder sb = new StringBuilder()
    parts.eachWithIndex { val, idx ->
        if (idx > 0) {
            sb.append(sep)
        }
        sb.append(val != null ? val.toString() : "")
    }
    return sb.toString()
}

rows.each { r ->
    Map row = r as Map
    String id = (row["_id"] != null) ? row["_id"].toString() : ""
    if (!id) {
        return
    }
    String chain = buildFullChain(id, idToParent, idToName, CHAIN_SEP)
    boolean hasChild = (childCountByParentId[id] ?: 0) > 0
    int mostSubVal = hasChild ? 0 : 1
    Map upd = [(F_FULL_CHAIN): chain, (F_IS_MOST_SUB): mostSubVal]
    def (Boolean uerr, Map udata, String umsg) = Fx.object.update(
            CATALOG_OBJ,
            id,
            upd,
            UpdateAttribute.builder().triggerWorkflow(false).build())
    if (uerr) {
        log.error("[产品目录自检] 更新失败 _id=" + id + " " + umsg)
    }
}
log.info("[产品目录自检] 完成")

/**
 * @author 纷享-曹树斌
 * @codeName 【流程】特殊配置类【商品】关联商机及T1
 * @description 根据 related_opportunity_id__c 查【商机】：写入 related_business_opportuni__c、t1_distributor__c；T1 来源为商机 T1_distributor__c
 * @createTime 2026-03-18
 * @bindingObjectLabel 商品
 * @bindingObjectApiName ProductObj
 * @函数需求编号
 */
String productId = context.data._id as String
String oppId = context.data.related_opportunity_id__c as String
log.info("[商品关联商机T1] productId=" + productId + ", related_opportunity_id__c=" + (oppId ?: ""))
if (!oppId) {
    log.info("[商品关联商机T1] 无所属商机ID，结束")
    return
}
Map opp = Fx.object.findById(
        "NewOpportunityObj",
        oppId,
        FQLAttribute.builder().columns(["_id", "name", "T1_distributor__c"]).build(),
        SelectAttribute.builder().build()).result() as Map
if (!opp) {
    log.error("[商品关联商机T1] 未查到商机，oppId=" + oppId)
    return
}
log.info("[商品关联商机T1] 商机 _id=" + (opp["_id"] ?: "") + ", name=" + (opp["name"] ?: "") + ", T1_distributor__c(raw)=" + opp["T1_distributor__c"])
Object t1Raw = opp["T1_distributor__c"]
String t1Id = ""
if (t1Raw instanceof List && (t1Raw as List).size() > 0) {
    t1Id = (t1Raw as List)[0] as String
} else if (t1Raw instanceof String) {
    t1Id = t1Raw as String
}
log.info("[商品关联商机T1] 解析后 t1Id=" + (t1Id ?: "(空)"))
Map upd = ["related_business_opportuni__c": oppId]
if (t1Id) {
    upd["t1_distributor__c"] = t1Id
}
log.info("[商品关联商机T1] 待写入 ProductObj upd=" + upd)
def (Boolean err, Map data, String msg) = Fx.object.update(
        "ProductObj",
        productId,
        upd,
        UpdateAttribute.builder().triggerWorkflow(true).build())
if (err) {
    log.error("[商品关联商机T1] 更新失败：" + msg)
} else {
    log.info("[商品关联商机T1] 更新成功，返回=" + data)
}

/**
 * @author 纷享-曹树斌
 * @codeName 【流程】商品所属产品目录
 * @description 取商品关联【产品型号】上的【产品目录】写回商品【产品目录】
 * @createTime 2026-03-18
 * @bindingObjectLabel 商品
 * @bindingObjectApiName ProductObj
 * @函数需求编号
 */
String productId = context.data._id as String
String productModelId = context.data.product_model__c as String
if (!productModelId) {
    return
}
def modelRow = Fx.object.findOne(
        "product_model__c",
        FQLAttribute.builder()
                .columns(["_id", "product_catalog__c"])
                .queryTemplate(QueryTemplate.AND(["_id": QueryOperator.EQ(productModelId)]))
                .build(),
        SelectAttribute.builder().build()).result() as Map
if (!modelRow) {
    log.error("未查到产品型号：" + productModelId)
    return
}
String catalogId = modelRow["product_catalog__c"] as String
if (!catalogId) {
    return
}
String currentCatalog = context.data.product_category_id as String
if (catalogId == currentCatalog) {
    return
}
def (Boolean uerr, Map udata, String umsg) = Fx.object.update(
        "ProductObj",
        productId,
        ["product_category_id": catalogId],
        UpdateAttribute.builder().triggerWorkflow(true).build())
if (uerr) {
    log.error("回写商品产品目录失败：" + umsg)
} else {
    log.info("已同步产品目录：" + catalogId)
}

/**
 * @author 纷享-曹树斌
 * @codeName 【按钮】推送订货单数据
 * @description 订货单数据推送到中电长城CRM
 * @createTime 2025-12-02
 * @bindingObjectLabel 订货单
 * @bindingObjectApiName purchase_order__c
 * @函数需求编号
 */

import com.fxiaoke.functions.http.Request
import com.fxiaoke.functions.http.StringBody
import com.fxiaoke.functions.http.HttpResult

String CONTRACT_URL = "https://rpt.greatwall.com.cn/forFxUatSer/v1/for/fxp/interface"
String objectAPIName = "purchase_order__c"

Map dataMap = context.data
String dataId = dataMap._id as String

log.info("开始推送订货单数据，ID: " + dataId)

// 获取产品明细数据（从context.details获取）
List productDetailList = context.details["purchase_order_product_dtl__c"] as List ?: []

// 如果context.details中没有，再从数据库查询
if (productDetailList.size() == 0) {
  try {
    def productResult = Fx.object.find(
      "purchase_order_product_dtl__c",
      FQLAttribute.builder()
        .columns(["_id", "productcommoditygoods__c", "crm_quotation_product_id__c", 
                  "quantity__c", "tax_included_unit_priceyua__c", "delivery_date__c", 
                  "configuration_info__c", "is_customized__c"])
        .queryTemplate(QueryTemplate.AND(["purchase_order__c": QueryOperator.EQ(dataId)]))
        .build(),
      SelectAttribute.builder().needInvalid(false).build()
    )

    if (!productResult.isError()) {
      QueryResult queryResult = productResult.result() as QueryResult
      productDetailList = queryResult["dataList"] as List ?: []
    }
  } catch (Exception e) {
    log.error("查询产品明细失败: " + e.getMessage())
  }
}

log.info("产品明细数量: " + productDetailList.size())

if (productDetailList.size() == 0) {
  log.error("订货单没有产品明细")
  Fx.message.throwException("订货单没有产品明细，无法推送")
}

// 获取用券明细数据（purchase_order_coupon_usage_detail__c）
List couponDetailList = []
try {
  def (Boolean couponErr, QueryResult couponResult, String couponMsg) = Fx.object.find(
    "purchase_order_coupon_usage_detail__c",
    FQLAttribute.builder()
      .columns(["_id", "rebate_coupon__c", "rebate_coupon_type__c",
                "remaining_available_balanc__c", "current_usage_amount__c"])
      .queryTemplate(QueryTemplate.AND(["order_form__c": QueryOperator.EQ(dataId)]))
      .build(),
    SelectAttribute.builder().needInvalid(false).build()
  )
  if (couponErr) {
    log.error("查询用券明细失败: " + couponMsg)
  } else {
    couponDetailList = couponResult?.dataList ?: []
    log.info("用券明细数量: " + couponDetailList.size())
  }
} catch (Exception e) {
  log.error("查询用券明细异常: " + e.getMessage())
}

// 返利券类型映射
Map COUPON_TYPE_MAP = [
  "option_stock_preparation_task_ach__c": "1",
  "option_promotion__c":                  "2",
  "option_price_protection__c":           "3"
]

// 格式化日期时间
String orderTimeStr = formatDateTime(dataMap["order_date__c"])

// 查询资金平台获取name
String platformName = ""
String fundPlatformId = context.data.fund_platform__c as String
if (fundPlatformId) {
  log.info("查询资金平台ID: " + fundPlatformId)
  def (Boolean platerror, QueryResult platResult, String platerrorMessage) = Fx.object.find(
    "fund_platform__c",
    FQLAttribute.builder()
      .columns(["_id", "name"])
      .queryTemplate(QueryTemplate.AND(["_id": QueryOperator.EQ(fundPlatformId)]))
      .build(),
    SelectAttribute.builder()
      .needInvalid(false)
      .build()
  )
  if (platerror) {
    log.error("查询资金平台失败: " + platerrorMessage)
  } else if (platResult.dataList && platResult.dataList.size() > 0) {
    Map platdata = platResult.dataList[0] as Map
    platformName = platdata.name as String ?: ""
    log.info("资金平台名称: " + platformName)
  }
} else {
  log.info("未关联资金平台")
}

// 构建主表数据（添加空值检查）
Map masterData = [
  // "fx_opp_id": dataMap["business_opportunity__c"] ?: "",
  "fx_contract_id": dataMap["_id"] ?: "",
  "fx_t1_id": dataMap["T1_distributor__c"] ?: "",
  "fx_customer_id": dataMap["end_customer__c"] ?: "",
  "is_platform": dataMap["is_funding_platform_approv__c"],
  "platform_credit_code": dataMap["fund_platform_social_credi__c"] ?: "",
  "platform_name": platformName,
  "order_time": orderTimeStr ?: "",
  "goods_receiver": dataMap["receiver_name__c"] ?: "",
  "receiver_phone": dataMap["consignee_phone__c"] ?: "",
  "receiver_address": dataMap["receiving_address__c"] ?: "",
  "is_customer_addr": dataMap["is_final_customer_address__c"] ?: "",
  "invoice_receipt": dataMap["invoice_requirement__c"] ?: "",
  "second_tax_rate": dataMap["invoice_tax_rate_percent__c"] ?: 0,
  "delay_days": dataMap["shipping_after_full_payment__c"] ?: 0
]

log.info("主表数据: " + Fx.json.toJson(masterData))

// 构建产品明细数据
List productsData = []
productDetailList.each { detail ->
  Map detailMap = detail as Map
  productsData.add([
    "goods_id": detailMap["product_id__c"] ?: "",
    "fx_product_id": detailMap["_id"] ?: "",
    "crm_quotation_product_id": detailMap["crm_quotation_product_id__c"] ?: "",
    "count": detailMap["quantity__c"] ?: 0,
    "with_tax_price": detailMap["tax_included_unit_priceyua__c"] ?: 0,
    "delivery_date": formatDateTime(detailMap["delivery_date__c"]),
    "conf_desc": detailMap["configuration_info__c"] ?: "",
    "list_price": detailMap["price_list_price__c"] ?: "",
    "is_customized": detailMap["is_customized__c"] ?: "2"
  ])
}

// 构建用券明细数据
List couponsData = []
couponDetailList.each { Object coupon ->
  Map couponMap = coupon as Map

  // 通过 rebate_coupon__c 关联字段查询返利券来源名称
  String couponName = ""
  String rebateCouponId = (couponMap.get("rebate_coupon__c") ?: "") as String
  log.info("用券明细记录: " + Fx.json.toJson(couponMap))
  log.info("关联返利券ID: " + rebateCouponId)
  if (rebateCouponId) {
    try {
      def (Boolean rcErr, Map rcData, String rcMsg) = Fx.object.findById(
        "rebate_coupon__c", rebateCouponId,
        FQLAttribute.builder().columns(["_id", "name", "rebate_coupon_source_name__c"]).build(),
        SelectAttribute.builder().build()
      )
      log.info("查询返利券结果: err=" + rcErr + " msg=" + rcMsg + " data=" + Fx.json.toJson(rcData))
      if (!rcErr && rcData) {
        couponName = (rcData.get("rebate_coupon_source_name__c") ?: rcData.get("name") ?: "") as String
      }
    } catch (Exception e) {
      log.error("查询返利券名称失败: " + e.getMessage())
    }
  }

  // 类型转换
  String typeRaw = (couponMap.get("rebate_coupon_type__c") ?: "") as String
  String typeVal = COUPON_TYPE_MAP.get(typeRaw) ?: ""

  couponsData.add([
    "id":               (couponMap.get("_id") ?: "") as String,
    "name":             couponName,
    "type":             typeVal,
    "available_amount": couponMap.get("remaining_available_balanc__c") ?: 0,
    "used_amount":      couponMap.get("current_usage_amount__c") ?: 0
  ])
}

// 组装请求数据
Map requestData = [
  "code": "F_FX_CONTRACT_ADD",
  "data": [
    "fx_opp_id": masterData["fx_opp_id"],
    "fx_contract_id": masterData["fx_contract_id"],
    "fx_t1_id": masterData["fx_t1_id"],
    "fx_customer_id": masterData["fx_customer_id"],
    "is_platform": masterData["is_platform"],
    "platform_credit_code": masterData["platform_credit_code"],
    "platform_name": masterData["platform_name"],
    "order_time": masterData["order_time"],
    "goods_receiver": masterData["goods_receiver"],
    "receiver_phone": masterData["receiver_phone"],
    "receiver_address": masterData["receiver_address"],
    "is_customer_addr": masterData["is_customer_addr"],
    "invoice_receipt": masterData["invoice_receipt"],
    "second_tax_rate": masterData["second_tax_rate"],
    "delay_days": masterData["delay_days"],
    "products": productsData,
    "coupons": couponsData
  ]
]

log.info("推送数据: " + Fx.json.toJson(requestData))

// 获取AccessToken
Map tokenInfo = GetAccessToken.getAccessToken()
if (!tokenInfo || !tokenInfo["accessToken"]) {
  log.error("获取accessToken失败")
  Fx.message.throwException("获取accessToken失败")
}

// 构建请求
StringBody body = StringBody.builder().content(Fx.json.toJson(requestData)).build()

Request request = Request.builder()
  .method("POST")
  .url(CONTRACT_URL)
  .timeout(30000)
  .retryCount(1)
  .header("Content-Type", "application/json")
  .header("accessToken", tokenInfo["accessToken"] as String)
  .body(body)
  .build()

// 发送请求
def httpResult = Fx.http.execute(request)

if (!httpResult || httpResult.size() < 2 || httpResult[1] == null) {
  String errorMsg = httpResult && httpResult.size() > 2 ? (httpResult[2] as String) : "未知错误"
  log.error("HTTP请求失败: " + errorMsg)
  Fx.message.throwException("推送失败: " + errorMsg)
}

HttpResult result = httpResult[1] as HttpResult

if (result.statusCode != 200) {
  log.error("HTTP请求失败，状态码: " + result.statusCode + ", 响应: " + result.content)
  Fx.message.throwException("推送失败，状态码: " + result.statusCode)
}

// 解析响应
Map resp = [:]
try {
  if (result.content instanceof String) {
    String contentStr = result.content as String
    log.info("响应原始内容: " + contentStr)

    if (contentStr.trim().startsWith("{") || contentStr.trim().startsWith("[")) {
      resp = Fx.json.parse(contentStr) as Map
    } else {
      log.error("响应不是有效的 JSON 格式，可能是错误页面")
      Fx.message.throwException("接口返回格式错误，请检查接口状态。响应内容: " + (contentStr.length() > 200 ? contentStr.substring(0, 200) + "..." : contentStr))
    }
  } else if (result.content instanceof Map) {
    resp = result.content as Map
  } else {
    log.error("响应内容类型不正确，无法解析")
    Fx.message.throwException("响应内容类型不正确，无法解析")
  }
} catch (Exception e) {
  log.error("响应解析失败: " + e.getMessage() + ", 响应内容: " + result.content)
  String errorMsg = "响应解析失败: " + e.getMessage()
  if (result.content instanceof String) {
    String contentStr = result.content as String
    errorMsg += "\n响应内容: " + (contentStr.length() > 500 ? contentStr.substring(0, 500) + "..." : contentStr)
  }
  Fx.message.throwException(errorMsg)
}

log.info("推送响应: " + Fx.json.toJson(resp))

// 处理返回结果
String flag = resp["flag"] as String
String msg = resp["msg"] as String

if ("true".equalsIgnoreCase(flag)) {
  log.info("推送成功: " + msg)

  Map updateData = [
    "status__c": "2",
    "sync_status__c":"成功",
    "sync_success_time__c": DateTime.now()
  ]

  def (Boolean error, Map data, String errorMessage) = 
    Fx.object.update(objectAPIName, dataId, updateData, UpdateAttribute.builder().triggerWorkflow(true).build())

  if (error) {
    log.error("更新状态失败: " + errorMessage)
    Fx.message.throwException("推送成功但更新状态失败: " + errorMessage)
  } else {
    log.info("状态更新成功")
    def lockResult = Fx.object.lock(objectAPIName, dataId, true)
    log.info("锁定记录: " + lockResult)
  }
} else {
  log.error("推送失败: " + msg)
  Fx.message.throwException("推送失败: " + (msg ?: "未知错误"))
}

/**
 * 格式化日期时间为字符串
 */
private String formatDateTime(Object dateTime) {
  if (dateTime == null) {
    return null
  }

  if (dateTime instanceof String) {
    return dateTime
  }

  if (dateTime instanceof DateTime) {
    DateTime dt = dateTime as DateTime
    String monthStr = dt.month < 10 ? "0" + dt.month : dt.month.toString()
    String dayStr = dt.day < 10 ? "0" + dt.day : dt.day.toString()
    String hourStr = dt.hour < 10 ? "0" + dt.hour : dt.hour.toString()
    String minuteStr = dt.minute < 10 ? "0" + dt.minute : dt.minute.toString()
    String secondStr = dt.second < 10 ? "0" + dt.second : dt.second.toString()
    return "${dt.year}-${monthStr}-${dayStr} ${hourStr}:${minuteStr}:${secondStr}"
  }

  return dateTime.toString()
}

/**
 * @author 纷享-曹树斌
 * @codeName 【工作流】根据crm更新的工号自动修改销售姓名
 * @description 1
 * @createTime 2026-03-13
 * @bindingObjectLabel T2经销商
 * @bindingObjectApiName t2_dealer__c
 * @函数需求编号
 */
String id = context.data._id as String
String salesJobNumber = context.data.sales_job_number_integrati__c as String
log.info("当前T2经销商id: " + id + ", 集成工号: " + salesJobNumber)

if (!salesJobNumber) {
  log.info("sales_job_number_integrati__c 为空，跳过")
  return
}

def ret = Fx.object.find(
  "channel_manager__c",
  FQLAttribute.builder()
    .columns(["_id", "name", "great_wall_work_number__c"])
    .queryTemplate(QueryTemplate.AND(["great_wall_work_number__c": QueryOperator.EQ(salesJobNumber)]))
    .build(),
  SelectAttribute.builder().build()
).result() as QueryResult

List dataList = ret.dataList as List
if (dataList.size() > 0) {
  String managerId = dataList[0]["_id"] as String
  String managerName = dataList[0]["name"] as String
  log.info("匹配到渠道经理: " + managerName + ", _id: " + managerId)

  Map updateData = [
    "great_wall_sales_name__c": managerId
  ]
  def (Boolean error, Map data, String errorMessage) = Fx.object.update(
    "t2_dealer__c",
    id,
    updateData,
    UpdateAttribute.builder().triggerWorkflow(false).build()
  )
  if (error) {
    log.error("更新T2经销商销售姓名失败: " + errorMessage)
  } else {
    log.info("更新成功，great_wall_sales_name__c -> " + managerName + "(" + managerId + ")，great_wall_sales_staff_id__c 将自动引用工号")
  }
} else {
