}

/**
 * @codeName 【按钮】推送T2认证申请
 * @description 向内部CRM推送T2认证申请数据（同T2经销商接收接口 F_FX_T2_ADD）
 * @bindingObjectLabel T2认证申请
 * @bindingObjectApiName t2_authentication_applicat__c
 */
import com.fxiaoke.functions.http.Request
import com.fxiaoke.functions.http.StringBody
import com.fxiaoke.functions.http.HttpResult

String GW_URL = "https://rpt.greatwall.com.cn/forFxUatSer/v1/for/fxp/interface"
String GW_CODE = "F_FX_T2_ADD"
String objectAPIName = "t2_authentication_applicat__c"
// 推送失败时写入此字段，供工作流场景下用户在详情页查看
String pushErrorFieldApi = "sync_status__c"
def writePushErrorToRecord = { String recordId, String errText ->
  try {
    Map updateMap = [(pushErrorFieldApi): errText] as Map<String, Object>
    def (Boolean upErr, Map upData, String upMsg) = Fx.object.update(objectAPIName, recordId, updateMap, UpdateAttribute.builder().triggerWorkflow(false).build())
    if (upErr) log.warn("写入推送错误到记录失败: " + upMsg)
  } catch (Exception e) {
    log.warn("写入推送错误失败: " + e.getMessage())
  }
}

Map dataMap = context.data
String dataId = dataMap._id as String

// 关联的 T2 经销商 ID（查找关联字段可能为字符串或单元素列表）
def rawDealer = dataMap["t2_dealer__c"]
String dealerId = null
if (rawDealer != null && rawDealer != "") {
  dealerId = rawDealer as String
}
if (!dealerId) {
  log.error("T2认证申请未关联T2经销商")
  Fx.message.throwException("请先关联T2经销商后再推送")
}


def (Boolean dealerErr, Map dealer, String dealerMsg) = Fx.object.findById(
  "t2_dealer__c",
  dealerId,
  FQLAttribute.builder()
    .columns([
      "_id", "name", "single_line_text__c", "organization_code__c",
      "registered_capital__c", "paidincapital__c", "number_of_employees_insure__c",
      "industrial_and_commercial__c", "business_address__c",
      "established_date__c", "field_E2o57__c", "great_wall_sales_staff_id__c"
    ])
    .build(),
  SelectAttribute.builder().build()
)
if (dealerErr || !dealer) {
  log.error("查询T2经销商失败: " + dealerMsg)
  Fx.message.throwException("查询关联T2经销商失败: " + (dealerMsg ?: "无数据"))
}

// 联系人：t2_distributor_contact_person__c 主从字段为 T2_dealer__c，按关联的 T2经销商 id 查询
List contactDetails = []
try {
  def (Boolean contactErr, QueryResult contactResult, String contactMsg) = Fx.object.find(
    "t2_distributor_contact_person__c",
    FQLAttribute.builder()
      .columns(["contact_name__c", "contact_phone__c", "email__c", "single_choice__c"])
      .queryTemplate(QueryTemplate.AND(["T2_dealer__c": QueryOperator.EQ(dealerId)]))
      .build(),
    SelectAttribute.builder().needInvalid(false).build()
  )
  if (!contactErr && contactResult?.dataList) {
    contactDetails = contactResult.dataList as List ?: []
  }
} catch (Exception e) {
  log.warn("查询T2经销商联系人失败: " + e.getMessage())
}
if (contactDetails.size() == 0) {
  log.error("关联的T2经销商没有联系人明细数据")
  Fx.message.throwException("关联的T2经销商没有联系人明细数据，无法推送")
}

List contacts = []
contactDetails.each { d ->
  Map m = d as Map
  contacts.add([
    "name": (m["contact_name__c"] ?: ""),
    "phone": (m["contact_phone__c"] ?: ""),
    "email": (m["email__c"] ?: ""),
    "type": (m["single_choice__c"] == "option_business_contact__c" ? "1" : "0")
  ])
}

// 附件转接口格式
def buildFiles = { Object fieldVal ->
  List files = []
  if (fieldVal instanceof List) {
    (fieldVal as List).each { it ->
      if (it instanceof Map) {
        Map m = it as Map
        String idv = (m["_id"] ?: m["id"] ?: m["path"] ?: "") as String
        String namev = (m["name"] ?: m["filename"] ?: "") as String
        if (idv) files.add(["file_id": idv, "file_name": namev])
      }
    }
  } else if (fieldVal instanceof Map) {
    Map m = fieldVal as Map
    String idv = (m["_id"] ?: m["id"] ?: m["path"] ?: "") as String
    String namev = (m["name"] ?: m["filename"] ?: "") as String
    if (idv) files.add(["file_id": idv, "file_name": namev])
  } else if (fieldVal instanceof String) {
    String idv = fieldVal as String
    if (idv && (idv.startsWith("N_") || idv.startsWith("TN_") || idv.startsWith("C_") || idv.startsWith("TC_"))) {
      files.add(["file_id": idv, "file_name": ""])
    }
  }
  return files
}

// 附件取自当前 T2认证申请 
List licenseInfo = buildFiles(dataMap["duplicateofbusinesslicense__c"])   // 营业执照副本(盖章)
List idcardInfo = buildFiles(dataMap["copy_of_legal_representati__c"])     // 法人身份证复印件
List insuredInfo = buildFiles(dataMap["insured_person_credentials__c"])   // 参保人员凭证
List financialInfo = buildFiles(dataMap["financial_statementaudit_r__c"])  // 财务报表(审计报告)

// 成立日期：关联T2.established_date__c，格式 yyyy-MM-dd
String establishDate = ""
Object et = dealer["established_date__c"]
try {
  if (et instanceof String) {
    String s = et as String
    establishDate = s.contains(" ") ? s.split(" ")[0] : s
  } else if (et != null) {
    Map em = Fx.json.parse(Fx.json.toJson(et)) as Map
    Integer y = (em.get("year") ?: 0) as Integer
    Integer m = (em.get("month") ?: 0) as Integer
    Integer d = (em.get("day") ?: 0) as Integer
    if (y > 0 && m > 0 && d > 0) {
      String ms = m < 10 ? ("0" + m) : ("" + m)
      String ds = d < 10 ? ("0" + d) : ("" + d)
      establishDate = y + "-" + ms + "-" + ds
    }
  }
} catch (Exception e) { establishDate = "" }

// 经营省份：根据关联T2.field_E2o57__c 查找（省API Name，见地区定位详细信息设置）
def rawRegion = dealer["field_E2o57__c"]
String regionCode = ""
if (rawRegion instanceof List && (rawRegion as List).size() > 0) {
  regionCode = (rawRegion as List)[0] as String
} else if (rawRegion instanceof Map) {
  regionCode = (rawRegion["_id"] ?: rawRegion["id"] ?: "") as String
} else if (rawRegion != null) {
  regionCode = rawRegion as String
}
String region_province = Fx.location.findCountryAreaLabel(regionCode, "province")
if (!region_province)
  region_province = regionCode
if (!region_province) {
  log.error("T2经销商省份为空，请检查 field_E2o57__c（省）")
  Fx.message.throwException("经营省份不能为空，请完善关联T2经销商的省/地区信息")
}

// 认证级别：agent_level__c 存储值即接口值（金牌=10，银牌=11，普通认证=12，其他=12）
String agentLevelRaw = (dataMap["agent_level__c"] ?: "") as String
String agentType = ("10".equals(agentLevelRaw) || "11".equals(agentLevelRaw) || "12".equals(agentLevelRaw)) ? agentLevelRaw : "12"
// 金牌/银牌时参保人员凭证、财务报表必传
if (("10".equals(agentType) || "11".equals(agentType)) && (insuredInfo.size() == 0 || financialInfo.size() == 0)) {
  log.error("认证级别为金牌或银牌时，参保人员凭证和财务报表(审计报告)为必填")
  Fx.message.throwException("认证级别为金牌或银牌时，参保人员凭证和财务报表(审计报告)为必填")
}

// 渠道经理工号：关联T2.great_wall_sales_staff_id__c
String saleNumber = (dealer["great_wall_sales_staff_id__c"] ?: "") as String

Map requestData = [
  "code": GW_CODE,
  "data": [
    "fx_id": dealerId,//T2经销商id
    "fx_apply_id":context.data["_id"],//T2认证申请id
    "name": dealer["name"],
    "credit_code": dealer["single_line_text__c"],
    "organization_code": dealer["organization_code__c"],
    "register_money": dealer["registered_capital__c"],
    "pay_money": dealer["paidincapital__c"],
    "insurance_personnel_count": dealer["number_of_employees_insure__c"],
    "registered_address": dealer["industrial_and_commercial__c"],
    "business_address": dealer["business_address__c"],
    "establish_date": establishDate,
    "province_name": region_province,
    "province_code": regionCode,
    "agent_type": agentType,
    "sale_number": saleNumber,
    "license_info": licenseInfo,
    "idcard_info": idcardInfo,
    "insured_info": insuredInfo,
    "financial_info": financialInfo,
    "contacts": contacts
  ]
]

log.info("推送T2认证申请数据，申请ID: " + dataId + ", 经销商ID: " + dealerId)
log.info("推送数据: " + Fx.json.toJson(requestData))

Map tokenInfo = GetAccessToken.getAccessToken()
if (!tokenInfo || !tokenInfo["accessToken"]) {
  log.error("获取accessToken失败")
  Fx.message.throwException("获取accessToken失败")
}

StringBody body = StringBody.builder().content(Fx.json.toJson(requestData)).build()
Request request = Request.builder()
  .method("POST")
  .url(GW_URL)
  .timeout(30000)
  .retryCount(1)
  .header("Content-Type", "application/json")
  .header("accessToken", tokenInfo["accessToken"] as String)
  .body(body)
  .build()

def httpResult = Fx.http.execute(request)
if (!httpResult || httpResult.size() < 2 || httpResult[1] == null) {
  String errorMsg = "推送失败: " + (httpResult && httpResult.size() > 2 ? (httpResult[2] as String) : "未知错误")
  log.error("HTTP请求失败: " + errorMsg)
  writePushErrorToRecord(dataId, errorMsg)
  Fx.message.throwException(errorMsg)
}

HttpResult result = httpResult[1] as HttpResult
if (result.statusCode != 200) {
  String statusErr = "推送失败，状态码: " + result.statusCode
  if (result.content instanceof String) {
    String contentStr = result.content as String
    if (contentStr.trim().startsWith("{")) {
      try {
        Map errResp = Fx.json.parse(contentStr) as Map
        String errMsg = (errResp["msg"] ?: errResp["message"] ?: "") as String
        if (errMsg) statusErr += "，" + errMsg
      } catch (Exception _) {}
    }
  }
  log.error("HTTP请求失败: " + statusErr)
  writePushErrorToRecord(dataId, statusErr)
  Fx.message.throwException(statusErr)
}

Map resp = [:]
try {
  if (result.content instanceof String) {
    String contentStr = result.content as String
    log.info("响应原始内容: " + contentStr)
    if (contentStr.trim().startsWith("{") || contentStr.trim().startsWith("[")) {
      resp = Fx.json.parse(contentStr) as Map
    } else {
      String parseErr = "接口返回格式错误，请检查接口状态。响应内容: " + (contentStr.length() > 200 ? contentStr.substring(0, 200) + "..." : contentStr)
      log.error("响应不是有效的 JSON 格式")
      writePushErrorToRecord(dataId, parseErr)
      Fx.message.throwException(parseErr)
    }
  } else if (result.content instanceof Map) {
    resp = result.content as Map
  } else {
    String typeErr = "响应内容类型不正确，无法解析"
    log.error(typeErr)
    writePushErrorToRecord(dataId, typeErr)
    Fx.message.throwException(typeErr)
  }
} catch (Exception e) {
  log.error("响应解析失败: " + e.getMessage() + ", 响应内容: " + result.content)
  String errorMsg = "响应解析失败: " + e.getMessage()
  if (result.content instanceof String) {
    String contentStr = result.content as String
    errorMsg += " 响应内容: " + (contentStr.length() > 300 ? contentStr.substring(0, 300) + "..." : contentStr)
  }
  writePushErrorToRecord(dataId, errorMsg)
  Fx.message.throwException(errorMsg)
}

log.info("推送响应: " + Fx.json.toJson(resp))

String flag = (resp["flag"] ?: resp["success"]) as String
String msg = (resp["msg"] ?: resp["message"] ?: "") as String
if ("true".equalsIgnoreCase(flag) || "success".equalsIgnoreCase(flag)) {
  log.info("推送成功: " + msg)
  Map updateData = [
    "status__c": "2",
    "sync_status__c":"",
    "sync_success_time__c": DateTime.now()
  ]
  def (Boolean error, Map data, String errorMessage) =
    Fx.object.update(objectAPIName, dataId, updateData, UpdateAttribute.builder().triggerWorkflow(true).build())
  if (error) {
    log.error("更新状态失败: " + errorMessage)
    Fx.message.throwException("推送成功但更新状态失败: " + errorMessage)
  } else {
    log.info("状态更新成功")
  }
  // 同步更新关联 T2 经销商的同步成功时间
  def (Boolean dealerUpErr, Map dealerUpData, String dealerUpMsg) =
    Fx.object.update("t2_dealer__c", dealerId, ["sync_success_time__c": DateTime.now()], UpdateAttribute.builder().triggerWorkflow(false).build())
  if (dealerUpErr) log.warn("更新T2经销商同步成功时间失败: " + dealerUpMsg)
} else {
  String errText = "推送失败: " + (msg ?: "未知错误")
  log.error(errText)
  writePushErrorToRecord(dataId, errText)
  Fx.message.throwException(errText)
}

/**
 * @author 纷享-曹树斌
 * @codeName 【按钮】推送特殊配置申请
 * @description 将特殊配置申请数据推送至内部crm接口
 * 推送成功后更新同步时间字段；失败时弹出错误提示。
 * @createTime 2026-03-02
 * @bindingObjectLabel 特殊配置申请
 * @bindingObjectApiName special_configuration_application__c
 * @函数需求编号
 */
import com.fxiaoke.functions.http.Request
import com.fxiaoke.functions.http.StringBody
import com.fxiaoke.functions.http.HttpResult

String URL = "https://rpt.greatwall.com.cn/forFxUatSer/v1/for/fxp/interface"
String objectAPIName = "special_configuration_application__c"

Map dataMap = context.data
String dataId = dataMap._id as String

log.info("[特配申请推送] 开始推送，记录ID=" + dataId)

// ── 处理附件字段（attachment__c）──
List attachment = []
Object platField = dataMap["attachment__c"]
if (platField instanceof List) {
  (platField as List).each { it ->
    if (it instanceof Map) {
      Map m = it as Map
      String idv  = (m["_id"] ?: m["id"] ?: m["path"] ?: "") as String
      String namev = (m["name"] ?: m["filename"] ?: "") as String
      attachment.add(["file_id": idv, "file_name": namev])
    }
  }
} else if (platField instanceof Map) {
  Map m = platField as Map
  String idv  = (m["_id"] ?: m["id"] ?: m["path"] ?: "") as String
  String namev = (m["name"] ?: m["filename"] ?: "") as String
  attachment.add(["file_id": idv, "file_name": namev])
} else if (platField instanceof String) {
  String idv = platField as String
  if (idv && (idv.startsWith("N_") || idv.startsWith("TN_") || idv.startsWith("C_") || idv.startsWith("TC_"))) {
    attachment.add(["file_id": idv, "file_name": ""])
  }
}
log.info("[特配申请推送] 附件数量=" + attachment.size() + "，内容=" + attachment)

// ── 必填字段校验 ──
String fxOppId      = dataMap["business_opportunity__c"] as String ?: ""
String demandRemark = dataMap["special_requirement_note__c"] as String ?: ""
if (!fxOppId)      Fx.message.throwException("商机字段（business_opportunity__c）为空，无法推送")
if (!demandRemark) Fx.message.throwException("特殊需求说明（special_requirement_note__c）为空，无法推送")

// ── 组装请求报文 ──
Map requestData = [
  "code": "F_FX_CFG_ADD",
  "data": [
    "fx_id"             : dataId,
    "fx_opp_id"         : fxOppId,
    "demand_remark"     : demandRemark,
    "demand_attachment" : attachment
  ]
]

String reqJson = Fx.json.toJson(requestData)
log.info("[特配申请推送] 请求Body=" + reqJson)

// ── 获取 accessToken ──
Map tokenInfo = GetAccessToken.getAccessToken()
if (!tokenInfo || !tokenInfo["accessToken"]) Fx.message.throwException("获取accessToken失败")

// ── 发送 HTTP 请求 ──
StringBody body = StringBody.builder().content(reqJson).build()
Request request = Request.builder()
  .method("POST")
  .url(URL)
  .timeout(30000)
  .retryCount(1)
  .header("Content-Type", "application/json")
  .header("accessToken", tokenInfo["accessToken"] as String)
  .body(body)
  .build()

def httpResult = Fx.http.execute(request)
if (!httpResult || httpResult.size() < 2 || httpResult[1] == null) {
  String errorMsg = httpResult && httpResult.size() > 2 ? (httpResult[2] as String) : "未知错误"
  Fx.message.throwException("推送失败: " + errorMsg)
}

HttpResult result = httpResult[1] as HttpResult
log.info("[特配申请推送] HTTP状态码=" + result.statusCode)
if (result.statusCode != 200) Fx.message.throwException("推送失败，状态码: " + result.statusCode)

// ── 解析响应 ──
Map resp = [:]
try {
  if (result.content instanceof String) {
    String contentStr = result.content as String
    log.info("[特配申请推送] 响应内容=" + contentStr)
    if (contentStr.trim().startsWith("{") || contentStr.trim().startsWith("[")) {
      resp = Fx.json.parse(contentStr) as Map
    } else {
      Fx.message.throwException("接口返回格式错误: " + contentStr)
    }
  } else if (result.content instanceof Map) {
    resp = result.content as Map
  } else {
    Fx.message.throwException("响应内容类型不正确")
  }
} catch (Exception e) {
  Fx.message.throwException("响应解析失败: " + e.getMessage())
}

String flag = (resp["flag"] ?: "") as String
String msg  = (resp["msg"]  ?: "") as String
log.info("[特配申请推送] flag=" + flag + "，msg=" + msg)

// ── 处理业务结果 ──
if ("true".equalsIgnoreCase(flag)) {
  // 推送成功 → 更新同步时间
  Map updateData = [
    "sync_success_time__c": DateTime.now()
  ]
  def (Boolean error, Map data, String errorMessage) =
    Fx.object.update(objectAPIName, dataId, updateData, UpdateAttribute.builder().triggerWorkflow(true).build())
  if (error) {
    Fx.message.throwException("推送成功但更新状态失败: " + errorMessage)
  }
  log.info("[特配申请推送] 推送成功，同步时间已更新")
  return "ok"
} else {
  Fx.message.throwException("推送失败: " + (msg ?: "未知错误"))
}

