List orderProductDetailIdList = [] //【订货单_产品明细】ID列表

log.info("返利生成政策："+rebatePolicyId+"，政策开始日期："+startDate+",政策结束日期："+endDate)
log.info("=========================查询该【返利生成政策】下的【返利生成政策_规则明细】================================")
//查询该【返利生成政策】下的【返利生成政策_规则明细】
def rebatePolicyRuleDetailRet = Fx.object.find(
  "rebate_generation_policy_dtl__c", //查询返利生成政策规则明细对象
  FQLAttribute.builder()
    .columns(["_id", "name", "rebate_policy_rule_type__c", "rebate_policy_rule_type__c__r", "rebate_policy_rule_type__c__o",
                "record_type","promotion_type__c","first_gear_step_limit__c","first_grade_step_rebate_am__c","second_gear_limit__c","second_grade_ladder_rebate__c",
                "third_gear_limit__c","third_gear_ladder_rebate_a__c","price_protection_rebate_am__c","exceed_current_gear_rebate__c"])
    .queryTemplate(QueryTemplate.AND(["rebate_generation_policy__c": QueryOperator.EQ(rebatePolicyId)]))
    .build(),
  SelectAttribute.builder()
    .needOptionLabel(true)
    .convertQuoteForView(true)
    .build()
