log.info("共查询到"+rebatePolicyRuleDetailRet.size+"条【返利生成政策_规则明细】：" + rebatePolicyRuleDetailRet)
List rebatePolicyRuleDetailList = rebatePolicyRuleDetailRet.dataList as List;
List rebatePolicyRuleDetailIdList = rebatePolicyRuleDetailList["_id"] as List;
rebatePolicyRuleDetailList.each {
  item ->
  rebatePolicyDetailMap.put(item["_id"] as String, item)
}
log.info("返利生成政策规则明细ID清单：" + rebatePolicyRuleDetailIdList)
log.info("===================查询该【返利生成政策_规则明细】下的【政策规则_参与订货产品】并按照T1分销商排序=========================")
//查询该【返利生成政策_规则明细】下的【政策规则_参与订货产品】并按照T1分销商排序
def policyRuleProductRet = Fx.object.find(
  "participation_dtl__c", //查询政策规则参与订货产品对象
  FQLAttribute.builder()
    .columns(["_id", "name", "order_form_product_detail__c", "T1_distributor__c","rebate_generation_policy_r__c"])
    .orderBy(["T1_distributor__c":1])
    .queryTemplate(QueryTemplate.AND(["rebate_generation_policy_r__c": QueryOperator.IN(rebatePolicyRuleDetailIdList)]))
    .build(),
  SelectAttribute.builder()
    .fillExtendInfo(true)
    .build()
).result() as QueryResult; 
log.info("共查询到"+policyRuleProductRet.size+"条【政策规则_参与订货产品】")
List policyRuleProductList = policyRuleProductRet.dataList as List;
log.info("【政策规则_参与订货产品】：" + policyRuleProductList)

policyRuleProductList.each {
  item ->
  String T1DistributorId = item["T1_distributor__c"] as String; //T1分销商ID
  //policyRuleProdMap.put(item["_id"],item["rebate_generation_policy_r__c"])//【政策规则_参与订货产品】ID
  t1IdNameMap.put(T1DistributorId, item["T1_distributor__c__r"] as String)//T1分销商名称
  orderProductDetailIdList.add(item["order_form_product_detail__c"] as String)//【订货单_产品明细】ID
  Map tempMap = ["orderProductdDetail":item["order_form_product_detail__c"],
                  "rebateGenPolicy":item["rebate_generation_policy_r__c"],
                  "orderProductdDetail_Label":item["order_form_product_detail__c__r"],
                  "rebateGenPolicy_Label":item["rebate_generation_policy_r__c__r"]]//临时Map，用于存储当前T1分销商关联的【订货单_产品明细】和【返利生成政策_规则明细】
  if( currentProcessingT1!=T1DistributorId){ //当前T1分销为新的，先处理之前的T1分销商关联的【订货单_产品明细】
    if( currentProcessingT1 != ""){
      t1OrderProductDetailMap.put(currentProcessingT1, orderProductDetailList)
      log.info("【T1分销商】【订货单_产品明细】：" + t1OrderProductDetailMap)
    }
    currentProcessingT1 = T1DistributorId
    orderProductDetailList.clear()//清空之前T1分销商关联的【订货单_产品明细】
    orderProductDetailList.add(tempMap)
  }else{
    orderProductDetailList.add(tempMap)
  }
}
t1OrderProductDetailMap.put(currentProcessingT1, orderProductDetailList)//最后一条数据处理
log.info("===========获取【订货单_产品明细】下所有关联的NCC发票明细，开票日期要在【返利生成政策】起止日期内=================")
//获取【订货单_产品明细】下所有关联的NCC发票明细，开票日期要在【返利生成政策】起止日期内
def nccInvoices = Fx.object.find(
  "ncc_invoice_detail__c", //查询政策规则参与订货产品对象
  FQLAttribute.builder()
    .columns(["_id", "name", "quantity__c","find_association__c"])
    .orderBy(["T1_distributor__c":1])
    .queryTemplate(QueryTemplate.AND(["find_association__c": QueryOperator.IN(orderProductDetailIdList)],
                                      ["date__c": QueryOperator.GTE(startDate)],
                                      ["date__c": QueryOperator.LTE(endDate)]
                                      ))
    .build(),
  SelectAttribute.builder()
    .build()
).result() as QueryResult; 

log.info("共查询到"+nccInvoices.size+"条NCC发票明细：" + nccInvoices.dataList)
List nccInvoiceList = nccInvoices.dataList as List
nccInvoiceList.each {
  item ->
  Map nccInvoice = item as Map
  String nccInvoiceId = nccInvoice._id as String
  String findAssociation = nccInvoice.find_association__c as String
  BigDecimal qantity = nccInvoice.quantity__c as BigDecimal
  prodDtlNCCMap.put(findAssociation, qantity)
  prodDtlNCCIdMap.put(findAssociation, nccInvoiceId)
}
log.info("NCC发票明细数量Map-【订货单_产品明细】:数量" + prodDtlNCCMap)

//按照T1分销商生成返利券
log.info("=========================按照T1分销商生成返利券================================")
t1OrderProductDetailMap.each {
  item ->
  String T1DistributorId = item.key as String
  log.info("正在为【"+ t1IdNameMap[T1DistributorId]+"】生成返利券...")
  orderProductDetailList = item.value as List
  Map rebatePolicyRuleDetailSum = [:]
  log.info("共有"+orderProductDetailList.size()+"条【订货单_产品明细】:"+orderProductDetailList.collect { it["orderProductdDetail_Label"]})
  orderProductDetailList.each {
    orderProductDetailItem ->
    Map orderProductDetail = orderProductDetailItem as Map
    String orderProductDetailId = orderProductDetail["orderProductdDetail"] as String
    String rebatePolicyRuleDetailId = orderProductDetail["rebateGenPolicy"] as String
    if ( rebatePolicyRuleDetailSum.containsKey(rebatePolicyRuleDetailId)){ //如果已经存在，累加数量
      BigDecimal tempQuantity = rebatePolicyRuleDetailSum[rebatePolicyRuleDetailId] as BigDecimal
      tempQuantity += prodDtlNCCMap[orderProductDetailId] as BigDecimal
      rebatePolicyRuleDetailSum.put(rebatePolicyRuleDetailId, tempQuantity)
    }else{
      rebatePolicyRuleDetailSum.put(rebatePolicyRuleDetailId, prodDtlNCCMap[orderProductDetailId] as BigDecimal)
    }
  }
  log.info("为【返利生成政策_规则明细】计算返利金额:"+rebatePolicyRuleDetailSum)
  rebatePolicyRuleDetailSum.each {
    rebatePolicyRuleDetailItem ->
    String rebatePolicyRuleDetailId = rebatePolicyRuleDetailItem.key as String
    Integer quantity = rebatePolicyRuleDetailItem.value as Integer
    Map policyRule = rebatePolicyDetailMap[rebatePolicyRuleDetailId] as Map
    BigDecimal totalAmount = 0 // 返利金额
    String recordType = policyRule["record_type"] as String // 促销:default__c ,价格保护:record_Pl0b2__c
    log.info("返利政策_规则明细Id:"+rebatePolicyRuleDetailId+"，数量:"+quantity+"，返利类型:"+(recordType == "default__c"? "促销": "价格保护"))
    if( recordType == "default__c"){
      String promotionType = policyRule["promotion_type__c"] as String // 促销类型
      Integer preMax = 0
      Integer remaining = quantity
      List tiers = [["max":policyRule["first_gear_step_limit__c"] as Integer,"price":policyRule["first_grade_step_rebate_am__c"] as BigDecimal]]
      if( promotionType == "option_two_gear_staircase__c"){
        tiers.add(["max":policyRule["second_gear_limit__c"] as Integer,"price":policyRule["second_grade_ladder_rebate__c"] as BigDecimal])
      }else if( promotionType == "option_three_gear_staircase__c"){
        tiers.add(["max":policyRule["second_gear_limit__c"] as Integer,"price":policyRule["second_grade_ladder_rebate__c"] as BigDecimal])
        tiers.add(["max":policyRule["third_gear_limit__c"] as Integer,"price":policyRule["third_gear_ladder_rebate_a__c"] as BigDecimal])
      }

      tiers.eachWithIndex { tier, idx ->
          if (remaining <= 0) return

          Integer tierCapacity = (tier.max as Integer) - preMax   // 当前档可容纳数量
          Integer countInTier = Math.min(remaining, tierCapacity)
          totalAmount += (countInTier * (tier.price as BigDecimal)) as BigDecimal
          remaining -= countInTier
          preMax = tier.max
      }

      if (remaining > 0) {
          Map highestTier = tiers.last()
          totalAmount += remaining * (policyRule["exceed_current_gear_rebate__c"] as BigDecimal)
      }
    }else if( recordType == "record_Pl0b2__c"){
      BigDecimal rebateAmount = policyRule["price_protection_rebate_am__c"] as BigDecimal
      totalAmount = rebateAmount * quantity as BigDecimal

    }else{
      log.info("未知返利生成类型")
    }
    log.info("总返利金额："+totalAmount+"，开始创建返利券...")
    Map masterData = [
            "T1_distributor__c"            : T1DistributorId, 
            "single_choice__c"             : recordType == "default__c"? "option_promotion__c": "option_price_protection__c", //单选字段   
            "rebate_generation_policy__c"  : rebatePolicyId as String,
            "rebate_generation_policy_r__c": rebatePolicyRuleDetailId,
            "rebate_coupon_amount__c"      : totalAmount,
            "status__c"                    :"option_not_effective__c",
            "record_type"                  :"default__c"
    ]

    List orderProdIdList = orderProductDetailList.collect { it["orderProductdDetail"]}
    List tempList =[]
    prodDtlNCCIdMap.each {
      key, value ->
      if( orderProdIdList.contains(key)){
        tempList.add(["ncc_invoice_detail__c": value,"record_type":"default__c"])
      }
    }
    Map detailData = [
            "rebate_coupon_generate_source__c": tempList
    ]
    def (Boolean cerror, Map cdata, String cerrorMessage) = Fx.object.create("rebate_coupon__c", masterData, detailData, CreateAttribute.builder().build())
    if(cerror){
      log.info("返利券创建失败："+cerrorMessage)
    }else{
      log.info("返利券创建成功！")
    }

  }
}

/**
 * @author 纷享-曹树斌
 * @codeName 【计划任务】备货任务-生成上季度备货任务返利
 * @description 计划任务条件：同时符合下述2个条件的【备货任务】才执行函数
·<年度/季度> = 上一个季度
·<任务完成率> 大于 100%
 * @createTime 2026-01-19
 * @bindingObjectLabel --
 * @bindingObjectApiName NONE
 * @函数需求编号
 */
//当前日期
Date nowDate = Date.now()
log.info("当前日期：" + nowDate)

//上季度起始日期和本季度起始日期
Integer year = nowDate.year as Integer
Integer month = nowDate.month as Integer
Integer quarter = 1
if (month <= 3)       quarter = 1
    else if (month <= 6)  quarter = 2
    else if (month <= 9)  quarter = 3
    else                  quarter = 4
Integer startMonth = (quarter - 2) * 3 + 1  // 1,4,7,10
Integer endMonth   = startMonth + 3          // 3,6,9,12
Integer startYear = year
Integer endYear = year
log.info("上一季度起始月："+startMonth+"，本季度起始月："+endMonth)
//季度结束日期需要处理跨年的情况，例如12月的季度结束日期为下一年的3月1日
if( endMonth > 12){
  endMonth = endMonth - 12
  endYear ++
}
if( startMonth <= 0){
  startMonth =startMonth + 12
  startYear --
}
Date startDate
Date endDate
if( startMonth < 10 ){
  startDate = Date.of(startYear + "-0" + startMonth + "-01") as Date
}else{
  startDate = Date.of(startYear + "-" + startMonth + "-01") as Date
}
if( endMonth < 10 ){
  endDate = Date.of(endYear + "-0" + endMonth + "-01") as Date
}else{
  endDate = Date.of(endYear + "-" + endMonth + "-01") as Date
}

log.info("上季度开始日期："+startDate+",本季度开始日期："+endDate)
//获取满足条件的所有备货任务数据
//1. 年度/季度 大于等于 上季度起始日期 且 小于 本季度起始日期
//2. 任务完成率 大于 100%
def (boolean error, QueryResult data, String errorMessage) = Fx.object.find(
  "stockup_task__c",
  FQLAttribute.builder()
    .columns(["_id", "annual_quarter__c", "task_completion_rate__c","T1_distributor__c","estimated_rebate_amount__c"])
    .queryTemplate(QueryTemplate.AND(
    ["annual_quarter__c": QueryOperator.GTE(startDate)],
    ["annual_quarter__c": QueryOperator.LT(endDate)],
    ["task_completion_rate__c": QueryOperator.GT(100)]
  ))
    .build(),
  SelectAttribute.builder()
    .build()
);
if (error) {
  log.info("查询备货任务数据失败：" + errorMessage)
  return
}
if( data.size == 0){
  log.info("没有查到符合条件的备货任务，结束任务")
  return
}
List stockupTasks = data.dataList as List
log.info("查询备货任务数据成功：共查到"+ data.size + "条数据,数据明细：" + stockupTasks)
//查询关联的NCC发票明细数据并符合以下要求
//对冲标记=正常，单据状态=审批通过

List stockupIdList =  stockupTasks["_id"] as List
def (boolean error1, QueryResult data1, String errorMessage1) = Fx.object.find(
  "ncc_invoice_detail__c",
  FQLAttribute.builder()
    .columns(["_id", "name","find_association__c","stock_preparation_task__c"])
    .queryTemplate(QueryTemplate.AND(
    ["stock_preparation_task__c": QueryOperator.IN(stockupIdList)],
    ["hedge_mark__c": QueryOperator.EQ("0")],  //对冲标记=正常
    ["document_status__c": QueryOperator.EQ("2")] //单据状态=审批通过
  ))
    .build(),
  SelectAttribute.builder()
    .fillExtendInfo(true)
    .build()
);
if (error1) {
  log.info("查询NCC发票明细数据失败：" + errorMessage1)
  return
}
if( data1.size == 0 ){
  log.info("没有查到符合条件的NCC发票明细，结束任务")
  return
}
List nccInvoices = data1.dataList as List;
log.info("查询NCC发票明细数据成功：共查到"+ data1.size + "条数据,数据明细：" + nccInvoices)
log.info("开始生成返利券")
stockupTasks.each {
  item ->
  String stockupId = item["_id"] as String;
  log.info("当前处理的备货任务ID：" + stockupId)
  Map masterData = [
          "T1_distributor__c"        : item["T1_distributor__c"],                    //取【备货任务】的<T1分销商>
          "single_choice__c"         : "option_stock_preparation_task_ach__c",       //备货任务达成
