/**
 * @author 纷享-曹树斌
 * @codeName 【计划任务】NCC发票明细-生成上季度备货任务返利
 * @description 计划任务条件：同时符合下述2个条件的【备货任务】才执行函数
·<年度/季度> = 上一个季度
·<任务完成率> 大于 100%

函数：基于每一条【备货任务】，找到其下关联的_且同时符合下述所有条件的_所有【NCC发票明细】数据，来生成一条【返利券】及【返利券_生成来源明细】：
 * @createTime 2025-12-09
 * @bindingObjectLabel 备货任务
 * @bindingObjectApiName stockup_task__c
 * @函数需求编号
 */
//当前日期
Date nowDate = Date.now()
log.info("当前日期：" + nowDate)

//上季度起始日期和本季度起始日期
Integer year = nowDate.year as Integer
Integer month = nowDate.month as Integer
Integer quarter = 1
if (month <= 3)       quarter = 1
    else if (month <= 6)  quarter = 2
    else if (month <= 9)  quarter = 3
    else                  quarter = 4
Integer startMonth = (quarter - 2) * 3 + 1  // 1,4,7,10
Integer endMonth   = startMonth + 3          // 3,6,9,12
Integer startYear = year
Integer endYear = year
log.info("上一季度起始月："+startMonth+"，本季度起始月："+endMonth)
//季度结束日期需要处理跨年的情况，例如12月的季度结束日期为下一年的3月1日
if( endMonth > 12){
  endMonth = endMonth - 12
  endYear ++
}
if( startMonth <= 0){
  startMonth =startMonth + 12
  startYear --
}
Date startDate
Date endDate
if( startMonth < 10 ){
  startDate = Date.of(startYear + "-0" + startMonth + "-01") as Date
}else{
  startDate = Date.of(startYear + "-" + startMonth + "-01") as Date
}
if( endMonth < 10 ){
  endDate = Date.of(endYear + "-0" + endMonth + "-01") as Date
}else{
  endDate = Date.of(endYear + "-" + endMonth + "-01") as Date
}

log.info("上季度开始日期："+startDate+",本季度开始日期："+endDate)
//获取满足条件的所有备货任务数据
//1. 年度/季度 大于等于 上季度起始日期 且 小于 本季度起始日期
//2. 任务完成率 大于 100%
def (boolean error, QueryResult data, String errorMessage) = Fx.object.find(
  "stockup_task__c",
  FQLAttribute.builder()
    .columns(["_id", "annual_quarter__c", "task_completion_rate__c","T1_distributor__c","estimated_rebate_amount__c"])
    .queryTemplate(QueryTemplate.AND(
    ["annual_quarter__c": QueryOperator.GTE(startDate)],
    ["annual_quarter__c": QueryOperator.LT(endDate)],
    ["task_completion_rate__c": QueryOperator.GT(100)]
  ))
    .build(),
  SelectAttribute.builder()
    .build()
);
if (error) {
  log.info("查询备货任务数据失败：" + errorMessage)
  return
}
if( data.size == 0){
  log.info("没有查到符合条件的备货任务，结束任务")
  return
}
List stockupTasks = data.dataList as List
log.info("查询备货任务数据成功：共查到"+ data.size + "条数据,数据明细：" + stockupTasks)
//查询关联的NCC发票明细数据并符合以下要求
//对冲标记=正常，单据状态=审批通过

List stockupIdList =  stockupTasks["_id"] as List
def (boolean error1, QueryResult data1, String errorMessage1) = Fx.object.find(
  "ncc_invoice_detail__c",
  FQLAttribute.builder()
    .columns(["_id", "name","find_association__c","stock_preparation_task__c"])
    .queryTemplate(QueryTemplate.AND(
    ["stock_preparation_task__c": QueryOperator.IN(stockupIdList)],
    ["hedge_mark__c": QueryOperator.EQ("0")],  //对冲标记=正常
    ["document_status__c": QueryOperator.EQ("2")] //单据状态=审批通过
  ))
    .build(),
  SelectAttribute.builder()
    .fillExtendInfo(true)
    .build()
);
if (error1) {
  log.info("查询NCC发票明细数据失败：" + errorMessage1)
  return
}
if( data1.size == 0 ){
  log.info("没有查到符合条件的NCC发票明细，结束任务")
  return
}
List nccInvoices = data1.dataList as List;
log.info("查询NCC发票明细数据成功：共查到"+ data1.size + "条数据,数据明细：" + nccInvoices)
log.info("开始生成返利券")
stockupTasks.each {
  item ->
  String stockupId = item["_id"] as String;
  log.info("当前处理的备货任务ID：" + stockupId)
  Map masterData = [
          "T1_distributor__c"        : item["T1_distributor__c"],                    //取【备货任务】的<T1分销商>
          "single_choice__c"         : "option_stock_preparation_task_ach__c",       //备货任务达成
          "stock_preparation_task__c": stockupId,                                    //写入【备货任务】主属性
          "rebate_coupon_amount__c"  : item["estimated_rebate_amount__c"],           //写入【备货任务】的<预计返利金额>的值
          "status__c"                : "option_not_effective__c"                     //选项=未生效
  ]
  List couponSourceDetails = []
  nccInvoices.each { 
    nccInvoice ->
    Map nccInvoiceMap = nccInvoice as Map;
    String nccInvoiceId = nccInvoiceMap["_id"] as String;
    Map tempMap = ["ncc_invoice_detail__c":nccInvoiceId]
    couponSourceDetails.add(tempMap)
  }
  Map detailData = [ "rebate_coupon_generate_source__c": couponSourceDetails ]
  log.info("开始生成返利券,返利券主数据："+masterData+",返利券明细："+detailData)
  def (Boolean error2, Map data2, String errorMessage2) = Fx.object.create("rebate_coupon__c", masterData, detailData, CreateAttribute.builder().build())
