/**
 * @author 纷享-曹树斌
 * @codeName 【公共类】上传附件
 * @description 中电长城附件上传公共类
 * @createTime 2025-12-01
 * @bindingObjectLabel --
 * @bindingObjectApiName NONE
 * @函数需求编号
 */
/**
 * @type classes
 * @returntype
 * @namespace library
 */
class UploadFile {

  static String FILE_UPLOAD_URL = "https://rpt.greatwall.com.cn/forFxUatSer/v1/for/fxp/file"

  /**
   * 批量上传附件
   * @param masterFieldVal 主对象数据
   * @param attachmentField 附件字段名称
   * @return Map {flag, msg, code, successList, failList}
   */
  static Map uploadContractFiles(Map masterFieldVal, String attachmentField = "contract_attachment") {
    if (!masterFieldVal || !masterFieldVal["_id"]) {
      return ["flag": "false", "msg": "数据或ID为空", "code": 500]
    }

    List attachments = masterFieldVal[attachmentField] as List ?: []
    log.info("附件字段: " + attachmentField + ", 附件数量: " + attachments.size())

    if (attachments.size() == 0) {
      return ["flag": "true", "msg": "没有附件需要上传", "code": 200]
    }

    Map tokenInfo = GetAccessToken.getAccessToken()
    if (!tokenInfo || !tokenInfo["accessToken"]) {
      log.error("获取accessToken失败")
      return ["flag": "false", "msg": "获取accessToken失败", "code": 500]
    }

    List successList = []
    List failList = []

    attachments.eachWithIndex { Object fileObj, int i ->
      Map fileMap = fileObj as Map
      String fileId = fileMap["path"] as String
      String fileName = fileMap["filename"] as String

      if (!fileId) {
        failList.add(["file_name": fileName, "msg": "文件ID为空"])
        return
      }

      log.info("上传附件 [" + (i + 1) + "/" + attachments.size() + "]: " + fileName)

      Map uploadResult = uploadSingle(fileId, fileName, tokenInfo["accessToken"] as String)

      if (uploadResult["code"] == 200) {
        successList.add(["file_id": fileId, "file_name": fileName])
      } else {
        failList.add(["file_name": fileName, "msg": uploadResult["msg"]])
        log.error("上传失败: " + fileName + " - " + uploadResult["msg"])
      }
    }

    if (failList.size() > 0) {
      return [
        "flag": "false",
        "msg": "部分文件推送失败: " + failList.collect { it["file_name"] }.join(", "),
        "code": 500,
        "successList": successList,
        "failList": failList
      ]
    }

    log.info("所有附件上传成功，共 " + successList.size() + " 个")
    return [
      "flag": "true",
      "msg": "附件上传成功。",
      "code": 200,
      "successList": successList
    ]
  }

  /**
   * 上传单个附件
   */
  private static Map uploadSingle(String fileId, String fileName, String accessToken) {
    def(Boolean downloadError, Object fileData, String downloadMsg) = Fx.file.downloadStream(fileId)
    if (downloadError) {
      return ["code": 500, "msg": "下载文件失败: " + downloadMsg]
    }

    InputStream inputStream = fileData["inputStream"] as InputStream
    if (!inputStream) {
      return ["code": 500, "msg": "文件流为空"]
    }

    MultipartBody body = MultipartBody.builder()
      .addPart("file_id", fileId)
      .addPart("file_name", fileName)
      .addPart("file", inputStream, fileName, "application/octet-stream")
      .build()

    Request request = Request.builder()
      .method("POST")
      .url(FILE_UPLOAD_URL)
      .timeout(30000)
      .retryCount(1)
      .header("Content-Type", "multipart/form-data")
      .header("accessToken", accessToken)
      .body(body)
      .build()

    def httpResult = Fx.http.execute(request)
    if (!httpResult || httpResult.size() < 2 || httpResult[1] == null) {
      String errorMsg = httpResult && httpResult.size() > 2 ? (httpResult[2] as String) : "未知错误"
      return ["code": 500, "msg": "HTTP请求失败: " + errorMsg]
    }

    HttpResult result = httpResult[1] as HttpResult
    if (result.statusCode != 200) {
      log.error("HTTP状态码: " + result.statusCode + ", 响应: " + result.content)
      return ["code": 500, "msg": "HTTP请求失败，状态码: " + result.statusCode]
    }

    Map resp = [:]
    try {
      resp = (result.content instanceof String) ? 
        (Fx.json.parse(result.content as String) as Map) : 
        (result.content as Map)
    } catch (Exception e) {
      return ["code": 500, "msg": "响应解析失败: " + e.getMessage()]
    }

    String flag = resp["flag"] as String
    String msg = resp["msg"] as String

    return ("true".equalsIgnoreCase(flag)) ? 
      ["code": 200, "msg": msg ?: "文件推送成功"] : 
      ["code": 500, "msg": msg ?: "文件推送失败"]
  }

  static void main(String[] args) {
    log.info("上传附件公共类")
  }
}

/**
 * @author 纷享-曹树斌
 * @codeName 【集成】订货单-单章合同文件接收接口
 * @description 订货单单章合同文件接收接口
 * @createTime 2025-12-08
 * @bindingObjectLabel 订货单
