 * @函数需求编号
 */
import com.fxiaoke.functions.http.Request
import com.fxiaoke.functions.http.StringBody
import com.fxiaoke.functions.http.HttpResult

String INTERFACE_URL = "https://rpt.greatwall.com.cn/forFxUatSer/v1/for/fxp/interfacee"

Map dataMap = context.data as Map
String fxContractId = dataMap._id as String

if (!fxContractId) {
  Fx.message.throwException("订货单ID为空")
}

List rawList = dataMap["distributor_single_chapter__c"] as List ?: []
List attachments = []
rawList.each { item ->
  Map m = item as Map
  String path = m["path"] as String
  String filename = m["filename"] as String
  if (path && filename) {
    attachments.add([
      "file_id": path,
      "file_name": filename
    ])
  }
}

if (attachments.size() == 0) {
  Fx.message.throwException("单章合同附件为空，无法推送")
}

Map requestData = [
  "code": "F_FX_CONTRACT_FILE",
  "data": [
    "fx_contract_id": fxContractId,
    "contract_attachment": attachments
  ]
]

Map tokenInfo = GetAccessToken.getAccessToken()
if (!tokenInfo || !tokenInfo["accessToken"]) {
  Fx.message.throwException("获取accessToken失败")
}

StringBody body = StringBody.builder().content(Fx.json.toJson(requestData)).build()

Request request = Request.builder()
  .method("POST")
  .url(INTERFACE_URL)
  .timeout(30000)
  .retryCount(1)
  .header("Content-Type", "application/json")
  .header("accessToken", tokenInfo["accessToken"] as String)
  .body(body)
  .build()

def httpResult = Fx.http.execute(request)

if (!httpResult || httpResult.size() < 2 || httpResult[1] == null) {
  String errorMsg = httpResult && httpResult.size() > 2 ? (httpResult[2] as String) : "未知错误"
  Fx.message.throwException("接口调用失败: " + errorMsg)
}

HttpResult result = httpResult[1] as HttpResult
if (result.statusCode != 200) {
  Fx.message.throwException("接口状态码错误: " + result.statusCode)
}

Map resp = [:]
try {
  if (result.content instanceof String) {
    resp = Fx.json.parse(result.content as String) as Map
  } else if (result.content instanceof Map) {
    resp = result.content as Map
  }
} catch (Exception e) {
  Fx.message.throwException("响应解析失败: " + e.getMessage())
}

String flag = resp["flag"] as String
String msg = resp["msg"] as String

if ("true".equalsIgnoreCase(flag)) {
  return ["code": 200, "msg": (msg ?: "订货单单章合同数据保存成功。")]
} else {
  return ["code": 500, "msg": (msg ?: ("订货单单章合同数据保存失败, 平台订货单id：" + fxContractId + "，异常原因：未知。"))]
}

