  Map tokenInfo = GetAccessToken.getAccessToken()
  if (!tokenInfo || !tokenInfo["accessToken"]) {
    log.error("获取AccessToken失败")
    return ["code": 500, "msg": "获取AccessToken失败"]
  }

  Map headers = [
    "Content-Type": "application/json",
    "accessToken": tokenInfo["accessToken"]
  ]

  // 发送HTTP请求
  try {
    StringBody body = StringBody.builder().content(requestData).build()

    Request.RequestBuilder requestBuilder = Request.builder()
      .method("POST")
      .url(CONTRACT_URL)
      .timeout(30000)
      .retryCount(1)
      .body(body)

    headers.each { key, value ->
      requestBuilder.header(key as String, value as String)
    }

    Request request = requestBuilder.build()

    def httpResult = Fx.http.execute(request)

    if (!httpResult || httpResult.size() < 2 || httpResult[1] == null) {
      log.error("HTTP请求失败")
      return ["code": 500, "msg": "HTTP请求失败"]
    }

    HttpResult result = httpResult[1] as HttpResult

    if (result.statusCode != 200) {
      log.error("HTTP请求失败，状态码: " + result.statusCode)
      return ["code": 500, "msg": "HTTP请求失败，状态码: " + result.statusCode]
    }

    // 解析响应
    Map resp = [:]
    try {
      if (result.content instanceof String) {
        resp = Fx.json.parse(result.content as String) as Map
      } else if (result.content instanceof Map) {
        resp = result.content as Map
      } else {
        log.error("响应格式不正确")
        return ["code": 500, "msg": "响应格式不正确"]
      }
    } catch (Exception e) {
      log.error("响应解析异常: " + e.getMessage())
      return ["code": 500, "msg": "响应解析失败"]
    }

    log.info("推送订货单 - 响应: " + Fx.json.toJson(resp))

    // 处理返回结果
    String flag = resp["flag"] as String
    String msg = resp["msg"] as String

    if ("true".equalsIgnoreCase(flag)) {
      return ["code": 200, "msg": msg ?: "订货单保存成功"]
    } else {
      return ["code": 500, "msg": msg ?: "订货单保存失败"]
    }

  } catch (Exception e) {
    log.error("推送订货单异常: " + e.getMessage())
    return ["code": 500, "msg": "推送异常: " + e.getMessage()]
  }
