def toDateStr = { Object v ->
  try {
    java.text.SimpleDateFormat sdf = new java.text.SimpleDateFormat("yyyy-MM-dd")
    if (v instanceof Number) {
      long ms = ((Number)v).longValue()
      return sdf.format(new java.util.Date(ms))
    }
    if (v instanceof String) {
      String s = (v as String).trim()
      if (s.matches("\\d+")) {
        long ms = Long.parseLong(s)
        return sdf.format(new java.util.Date(ms))
      }
      return s
    }
  } catch (Exception e) {}
  return null
}

def toInt = { Object v, int defVal ->
  try {
    if (v instanceof Number) return ((Number)v).intValue()
    if (v instanceof String) {
      String s = (v as String).trim()
      if (s.length() > 0) return Integer.parseInt(s)
    }
  } catch (Exception e) {}
  return defVal
}

