      log.error("响应不是有效的 JSON 格式，可能是错误页面")
      Fx.message.throwException("接口返回格式错误，请检查接口状态。响应内容: " + (contentStr.length() > 200 ? contentStr.substring(0, 200) + "..." : contentStr))
    }
  } else if (result.content instanceof Map) {
    resp = result.content as Map
  } else {
    log.error("响应内容类型不正确，无法解析")
    Fx.message.throwException("响应内容类型不正确，无法解析")
  }
} catch (Exception e) {
  log.error("响应解析失败: " + e.getMessage() + ", 响应内容: " + result.content)
  String errorMsg = "响应解析失败: " + e.getMessage()
  if (result.content instanceof String) {
    String contentStr = result.content as String
    errorMsg += "\n响应内容: " + (contentStr.length() > 500 ? contentStr.substring(0, 500) + "..." : contentStr)
  }
  Fx.message.throwException(errorMsg)
}

log.info("推送响应: " + Fx.json.toJson(resp))

// 处理返回结果
String flag = resp["flag"] as String
String msg = resp["msg"] as String

if ("true".equalsIgnoreCase(flag)) {
  log.info("推送成功: " + msg)

  // 更新状态为2并锁定
  Map updateData = [
    "status__c": "2",
    // "sync_status__c":"成功",
    "sync_success_time__c": DateTime.now()
  ]

  def (Boolean error, Map data, String errorMessage) = 
    Fx.object.update(objectAPIName, dataId, updateData, UpdateAttribute.builder().triggerWorkflow(true).build())

  if (error) {
    log.error("更新状态失败: " + errorMessage)
    Fx.message.throwException("推送成功但更新状态失败: " + errorMessage)
  } else {
    log.info("状态更新成功")

    // 锁定记录
    def lockResult = Fx.object.lock(objectAPIName, dataId, true)
    log.info("锁定记录: " + lockResult)
  }
} else {
  log.error("推送失败: " + msg)
  Fx.message.throwException("推送失败: " + (msg ?: "未知错误"))
}

private String mapPayWay(Object v) {
  String s = v as String
  if (!s) return "1"
  if (s.isNumber()) return s
  String lower = s.toLowerCase()
  if (lower.contains("cash") || s.contains("现款") || s.contains("现结")) return "1"
  return "2"
}

private String mapInvoiceType(Object v) {
  String s = v as String
  if (!s) return "2"
  if (s.isNumber()) return s
  if (s.contains("增值税")) return "2"
  if (s.contains("普通")) return "1"
  return "2"
}

/**
 * @author 系统管理员
 * @codeName 获取CRMAccessToken
 * @description 获取中电长城CRM访问令牌的公共工具类
 * @createTime 2025-11-26
 */

class GetAccessToken {

  // private static String TOKEN_URL = "https://rpt.greatwall.com.cn/forFxAuthSer/auth/token/password"
  private static String TOKEN_URL = "https://rpt.greatwall.com.cn/forFxUatAuthSer/auth/token/password"
  private static String CLIENT_ID = "xccrm"
  private static String USERNAME = "fx_integrate_auth"
  private static String PASSWORD = "GreatWall2020"

  /**
   * 获取CRM访问令牌
   * @return Map包含accessToken、refreshToken等信息，失败返回null
   */
  public static Map getAccessToken() {
    try {
      Map requestBody = [
        "grantType": "password",
        "clientId": CLIENT_ID,
        "username": USERNAME,
        "password": PASSWORD
      ]

      StringBody body = StringBody.builder().content(requestBody).build()

      Request request = Request.builder()
        .method("POST")
        .url(TOKEN_URL)
        .timeout(30000)
        .retryCount(1)
        .header("Content-Type", "application/json")
        .body(body)
        .build()

      def httpResult = Fx.http.execute(request)

      if (!httpResult || httpResult.size() < 2 || httpResult[1] == null) {
        log.error("HTTP请求失败")
        return null
      }

      HttpResult httpRes = httpResult[1] as HttpResult

      if (httpRes.statusCode != 200) {
        log.error("HTTP请求失败，状态码: " + httpRes.statusCode)
        return null
      }

      def content = httpRes.content

      if (content instanceof Map) {
        Map resp = content as Map
        Integer status = resp["status"] as Integer
        Boolean rel = resp["rel"] as Boolean

        if (status == 22002 && rel && resp["data"]) {
          Map data = resp["data"] as Map
          return [
            "accessToken": data["accessToken"],
            "refreshToken": data["refreshToken"],
            "expiresIn": data["expiresIn"],
            "tokenType": data["tokenType"]
          ]
        }
      }

      return null

    } catch (Exception e) {
      log.error("获取Token异常: " + e.getMessage())
      return null
    }
  }

  void debug(FunctionContext context, Map arg) {
    Map tokenInfo = getAccessToken()
    if (tokenInfo) {
      log.info("成功获取access token: " + tokenInfo["accessToken"])
    }
  }
}

