/**
 * @author 纷享-曹树斌
 * @codeName 自定义控制器-检查价目表明细价格状态
 * @description 检查选中的价目表明细中是否有价格状态为失效的商品
 * @createTime 2025-12-03
 * @bindingObjectLabel --
 * @bindingObjectApiName NONE
 * @函数需求编号
 */

// 自定义控制器函数
// 参数通过变量名直接访问：priceListDetailIds

// 检查参数是否存在
if (!priceListDetailIds) {
  return [
    "success": true,
    "data": [
      "hasInvalidPriceStatus": false,
      "invalidProducts": []
    ]
  ]
}

List ids = priceListDetailIds as List

if (ids.size() == 0) {
  return [
    "success": true,
    "data": [
      "hasInvalidPriceStatus": false,
      "invalidProducts": []
    ]
  ]
}

// 首先查询价目表明细，获取其关联的商品ID
def (Boolean detailError, QueryResult detailQueryResult, String detailErrorMsg) = Fx.object.find(
  "PriceBookProductObj",
  FQLAttribute.builder()
    .columns(["_id", "name", "product_id__c"])
    .queryTemplate(QueryTemplate.AND([
      "_id": QueryOperator.IN(ids)
    ]))
    .build(),
  SelectAttribute.builder()
    .needInvalid(false)
    .build()
)

if (detailError) {
  return [
    "success": false,
    "errorMessage": "查询价目表明细失败: " + detailErrorMsg
  ]
}

// 提取所有商品ID
List productIds = []
Map detailProductMap = [:] // 价目表明细ID -> 商品ID映射
detailQueryResult.dataList.each { detail ->
  Map detailMap = detail as Map
  String productId = detailMap["product_id__c"] as String
  if (productId) {
    productIds.add(productId)
    detailProductMap[detailMap["_id"] as String] = productId
  }
}

if (productIds.size() == 0) {
  return [
    "success": true,
    "data": [
      "hasInvalidPriceStatus": false,
      "invalidProducts": []
    ]
  ]
}

// 查询商品对象的价格状态
def (Boolean error, QueryResult queryResult, String errorMessage) = Fx.object.find(
  "ProductObj",
  FQLAttribute.builder()
    .columns(["_id", "name", "price_effect_status__c","product_id__c"])
    .queryTemplate(QueryTemplate.AND([
      "product_id__c": QueryOperator.IN(productIds)
    ]))
    .build(),
  SelectAttribute.builder()
    .needInvalid(false)
    .build()
)

if (error) {
  return [
    "success": false,
    "errorMessage": "查询商品对象失败: " + errorMessage
  ]
}

// 创建商品ID到商品信息的映射
Map productInfoMap = [:]
queryResult.dataList.each { product ->
  Map productMap = product as Map
  String productId = productMap["product_id__c"] as String
  Object priceStatusObj = productMap["price_effect_status__c"]
  String priceStatus = priceStatusObj ? (priceStatusObj as String) : ""
  Object productNameObj = productMap["name"]
  String productName = productNameObj ? (productNameObj as String) : ""

  // 使用put方法构建Map，避免类型推断问题
  Map productInfo = [:]
  productInfo.put("name", productName)
  productInfo.put("price_status", priceStatus)
  productInfoMap.put(productId, productInfo)
}

// 检查每个价目表明细关联的商品价格状态
List invalidProducts = []
detailProductMap.each { entry ->
  String detailId = entry.key as String
  String productId = entry.value as String
  Map productInfo = productInfoMap[productId] as Map

  if (!productInfo) {
    return // continue
  }

  String priceStatus = productInfo["price_status"] as String ?: ""
  String productName = productInfo["name"] as String ?: "未知商品"

  // 判断价格状态是否为失效：option_invalidated__c
  if (priceStatus == "option_invalidated__c") {
    invalidProducts.add([
      "price_list_detail_id": detailId,
      "product_id__c": productId,
      "product_name": productName,
      "price_status": priceStatus
    ])
  }
}

return [
  "success": true,
  "data": [
    "hasInvalidPriceStatus": invalidProducts.size() > 0,
    "invalidProducts": invalidProducts
  ]
]

